insert into feats (owner_user_id, source_id, visibility, slug, name, prerequisites, summary, description, mechanics, is_system_content)
values
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'athlete', 'Athlete', '{}'::text[], 'Mejora la capacidad fisica general y agiliza varios movimientos atleticos.', 'Seed inicial del SRD para representar una dote con mejora flexible de fuerza o destreza y notas de movilidad.', '[{"type":"choose_ability_bonus","count":1,"value":1,"allowed":["strength","dexterity"]},{"type":"note","text":"Standing up from prone uses only 5 feet of movement."},{"type":"note","text":"Climbing no longer costs extra movement, and you can make a running long jump or high jump after moving only 5 feet."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'heavily-armored', 'Heavily Armored', array['proficiency:armor:medium-armor']::text[], 'Entrenamiento adicional para usar armadura pesada.', 'Seed inicial del SRD para disponer de una dote centrada en competencia defensiva y mejora de caracteristica.', '[{"type":"ability_bonus","ability":"strength","value":1},{"type":"proficiency","proficiencyType":"armor","value":"heavy-armor"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'keen-mind', 'Keen Mind', '{}'::text[], 'Aumenta la agudeza mental y la capacidad de orientacion y recuerdo.', 'Seed inicial del SRD para disponer de una dote centrada en inteligencia y memoria excepcional.', '[{"type":"ability_bonus","ability":"intelligence","value":1},{"type":"note","text":"You always know which way is north and how many hours remain before the next sunrise or sunset."},{"type":"note","text":"You can accurately recall anything you have seen or heard within the past month."}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'resilient-constitution', 'Resilient (Constitution)', '{}'::text[], 'Refuerza la resistencia fisica y otorga competencia en salvaciones de constitucion.', 'Seed inicial del SRD para ampliar la familia de dotes de resiliencia con una opcion util para concentracion y aguante.', '[{"type":"ability_bonus","ability":"constitution","value":1},{"type":"proficiency","proficiencyType":"saving_throw","value":"constitution"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'resilient-wisdom', 'Resilient (Wisdom)', '{}'::text[], 'Refuerza la voluntad y otorga competencia en salvaciones de sabiduria.', 'Seed inicial del SRD para representar una dote orientada a caracteristicas y tiradas de salvacion.', '[{"type":"ability_bonus","ability":"wisdom","value":1},{"type":"proficiency","proficiencyType":"saving_throw","value":"wisdom"}]'::jsonb, true),
	(null, (select id from content_sources where code = 'srd-5-1'), 'public', 'observant', 'Observant', '{}'::text[], 'Aumenta la percepcion de detalles y la lectura de labios.', 'Seed inicial del SRD para representar una dote con mejora flexible de inteligencia o sabiduria y observacion reforzada.', '[{"type":"choose_ability_bonus","count":1,"value":1,"allowed":["intelligence","wisdom"]},{"type":"note","text":"You can read lips if you can see a creature''s mouth while it is speaking a language you understand."},{"type":"note","text":"You gain a +5 bonus to passive Wisdom (Perception) and passive Intelligence (Investigation)."}]'::jsonb, true)
